#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5;
mt19937 num(998244353);
int n,m,cnt,root;
struct FHQ_Trp{
    int ls,rs;//左子树，右子树
    int val,key;//权值以及随机索引
    int sz;//子树大小
    bool tag;//懒标记
}tree[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int New_node(int k){
    ++cnt;
    tree[cnt].val=k;
    tree[cnt].key=num();
    tree[cnt].sz=1;
    return cnt;
}
void push_down(int u){
    if(!tree[u].tag)return;
    swap(tree[u].ls,tree[u].rs);
    tree[tree[u].ls].tag^=1;
    tree[tree[u].rs].tag^=1;
    tree[u].tag=0;return;
}
void upd(int u){
    tree[u].sz=tree[tree[u].ls].sz+tree[tree[u].rs].sz+1;return;
}
void Split(int u,int k,int &x,int &y){
    if(!u){x=0,y=0;return;}
    push_down(u);
    if(tree[tree[u].ls].sz+1<=k){
        x=u;
        Split(tree[u].rs,k-tree[tree[u].ls].sz-1,tree[u].rs,y);
    }else{
        y=u;
        Split(tree[u].ls,k,x,tree[u].ls);
    }upd(u);return;
}
int Merge(int x,int y){
    if(!x||!y)return x+y;
    if(tree[x].key>tree[y].key){
        push_down(x);
        tree[x].rs=Merge(tree[x].rs,y);
        upd(x);return x;
    }else{
        push_down(y);
        tree[y].ls=Merge(x,tree[y].ls);
        upd(y);return y;
    }
}
void Insert(int k){
    int x=0,y=0;
    Split(root,k,x,y);
    root=Merge(Merge(x,New_node(k)),y);
    return;
}
void Delete(int k){
    int x=0,y=0,z=0;
    Split(root,k,x,z);
    Split(x,k-1,x,y);
    y=Merge(tree[y].ls,tree[y].rs);
    root=Merge(Merge(x,y),z);
    return;
}
void Sol(int l,int r){
    int x=0,y=0,z=0;
    Split(root,r,x,z);
    Split(x,l-1,x,y);
    tree[y].tag^=1;
    root=Merge(Merge(x,y),z);
    return;
}
void DFS(int u){
    if(!u)return;
    push_down(u);
    DFS(tree[u].ls);
    cout<<tree[u].val<<" ";
    DFS(tree[u].rs);
    return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)Insert(i);
    for(int i=1;i<=m;i++){
        int l=read(),r=read();
        Sol(l,r);
    }DFS(root);cout<<"\n";
    return 0;
}
